578→#[cfg(test)]
579→mod proptests {
580→    use super::*;
581→    use proptest::prelude::*;
582→    use crate::execution_record::{BranchDecision, SymConstraint};
583→    use crate::protocol::{ExecuteResult, PerformanceMetrics};
584→
585→    /// Generate a random BranchDecision with a given branch_id.
586→    fn arb_branch_decision(max_id: u32) -> impl Strategy<Value = BranchDecision> {
587→        (0..max_id, any::<bool>()).prop_map(|(id, taken)| BranchDecision {
588→            branch_id: id,
589→            line: id * 10,
590→            taken,
591→            constraint: SymConstraint::Unknown {
592→                hint: String::new(),
593→            },
594→        })
595→    }
596→
597→    /// Generate a random ExecuteResult with up to `max_branches` branches.
598→    fn arb_exec_result(max_branches: usize) -> impl Strategy<Value = ExecuteResult> {
599→        let branches = proptest::collection::vec(arb_branch_decision(20), 0..max_branches);
600→        let lines = proptest::collection::vec(1..200u32, 0..10);
601→
602→        (branches, lines).prop_map(|(branch_path, lines_executed)| ExecuteResult {
603→            return_value: Some(serde_json::json!(0)),
604→            thrown_error: None,
605→            branch_path,
606→            lines_executed,
607→            calls_to_external: vec![],
608→            path_constraints: vec![],
609→            scope_events: vec![],
610→            side_effects: vec![],
611→            performance: PerformanceMetrics {
612→                wall_time_ms: 1.0,
613→                cpu_time_us: 1000,
614→                heap_used_bytes: 0,
615→                heap_allocated_bytes: 0,
616→            },
617→            capture_truncation: None,
618→        })
619→    }
620→
621→    proptest! {
622→        /// The number of unique paths equals the number of distinct path_hash values.
623→        #[test]
624→        fn unique_paths_equals_distinct_hashes(
625→            results in proptest::collection::vec(arb_exec_result(5), 1..20)
626→        ) {
627→            let buckets = LoopBuckets::none();
