/// Tracks execution results, deduplicates paths, and accumulates discovery
/// attribution. Shared between `observe_batch` (observe.rs) and
/// `explore_function` so that classification logic has a single source of truth.
pub(crate) struct ExecutionTracker {
    seen_paths: HashSet<u64>,
    all_lines: HashSet<u32>,
    seen_branch_ids: HashSet<u32>,
    discoveries: Vec<(u32, DiscoveryMethod)>,
    new_path_executions: Vec<ExecutionSummary>,
    raw_results: Vec<(Vec<serde_json::Value>, Vec<MockConfig>, ExecuteResult)>,
    loop_buckets: LoopBuckets,
}

impl ExecutionTracker {
    pub(crate) fn new(loop_buckets: LoopBuckets) -> Self {
        Self {
            seen_paths: HashSet::new(),
            all_lines: HashSet::new(),
            seen_branch_ids: HashSet::new(),
            discoveries: Vec::new(),
            new_path_executions: Vec::new(),
            raw_results: Vec::new(),
            loop_buckets,
        }
    }

    /// Record one execution result. Returns `true` if this was a new unique path.
    pub(crate) fn record(
        &mut self,
        inputs: Vec<serde_json::Value>,
        mocks: Vec<MockConfig>,
        result: ExecuteResult,
    ) -> bool {
        for &line in &result.lines_executed {
            self.all_lines.insert(line);
        }

        let hash = path_hash(&result, &self.loop_buckets);
        let is_new = self.seen_paths.insert(hash);

        for decision in &result.branch_path {
            if self.seen_branch_ids.insert(decision.branch_id) {
                self.discoveries
                    .push((decision.branch_id, DiscoveryMethod::Random));
            }
        }

        if is_new {
            let error_intent = classify_error_intent(&result);
            self.new_path_executions.push(ExecutionSummary {
                inputs: inputs.clone(),
                return_value: result.return_value.clone(),
                thrown_error: result
                    .thrown_error
                    .as_ref()
                    .map(|e| format!("{}: {}", e.error_type, e.message)),
                lines_executed: result.lines_executed.clone(),
                is_new_path: true,
                error_intent,
            });
        }

        self.raw_results.push((inputs, mocks, result));
        is_new
    }

    /// Access the set of unique path hashes seen so far.
    pub(crate) fn seen_paths(&self) -> &HashSet<u64> {
        &self.seen_paths
    }

    /// Access the set of covered lines.
    pub(crate) fn lines_covered(&self) -> &HashSet<u32> {
        &self.all_lines
    }

    /// Record a line as covered (used by float probing which tracks lines
    /// outside the normal record() flow).
    pub(crate) fn add_line(&mut self, line: u32) {
        self.all_lines.insert(line);
    }

    /// Record a path hash as seen (used by float probing).
    pub(crate) fn add_path(&mut self, hash: u64) {
        self.seen_paths.insert(hash);
    }

    /// Consume into the fields needed by `ObservationOutput` and `BatchObservation`.
    pub(crate) fn finish(
        self,
    ) -> (
        HashSet<u64>,
        HashSet<u32>,
        Vec<(u32, DiscoveryMethod)>,
        Vec<ExecutionSummary>,
        Vec<(Vec<serde_json::Value>, Vec<MockConfig>, ExecuteResult)>,
    ) {
        (
            self.seen_paths,
            self.all_lines,
            self.discoveries,
            self.new_path_executions,
            self.raw_results,
        )
    }
}

