        assert_eq!(b.bucket(2), 2); // bucket 2: count=2
        assert_eq!(b.bucket(3), 3); // bucket 3: count=3 (3-5 range)
        assert_eq!(b.bucket(4), 3);
        assert_eq!(b.bucket(5), 3);
        assert_eq!(b.bucket(6), 4); // bucket 4: count=6+ (overflow)
