                return Err(ObserveError::UnexpectedResponse(format!(
                    "expected Execute response, got {other:?}"
                )));
            }
        };

        // Per-execution teardown
        if frontend_supports(&config.capabilities, "teardown") {
            send_teardown(frontend, &analysis.name, config.setup_level).await?;
        }

        tracker.record(input, config.mocks.clone(), exec_result);
    }

    let (unique_path_hashes, lines_covered, discoveries, new_path_executions, raw_results) =
        tracker.finish();

    Ok(BatchObservation {
        raw_results,
        unique_path_hashes,
        lines_covered,
        discoveries,
        new_path_executions,
    })
}

