  1→//! Stage 1 (Observe): Execute a function with pre-generated inputs and collect
  2→//! execution traces. Pure observation — no Z3 or constraint solving.
  3→//!
  4→//! The observe module provides a composable building block: given a function and
  5→//! a list of inputs, it executes each input via the language frontend and returns
  6→//! structured trace data (branch coverage, line coverage, side effects, discovery
  7→//! attribution). Callers are responsible for generating inputs (random, boundary,
  8→//! user-provided) before calling into this module.
  9→
 10→use std::collections::HashSet;
 11→use std::time::{Duration, Instant};
 12→
 13→use serde::{Deserialize, Serialize};
 14→
 15→use crate::protocol::SetupLevel;
 16→use crate::protocol::SetupContextStack;
 17→use crate::coverage_metrics::DiscoveryMethod;
 18→use crate::explorer::{
 19→    classify_error_intent, frontend_supports, path_hash, send_setup, send_teardown,
 20→    ExecutionSummary, ExploreError, LoopBuckets, ObservationOutput,
 21→};
 22→use crate::frontend::{Frontend, FrontendError};
 23→use crate::orchestrator::FrontendCapabilities;
 24→use crate::protocol::{
 25→    Command as ProtoCommand, ExecuteResult, FunctionAnalysis, MockConfig, ResponseResult,
 26→};
 27→
 28→/// Errors that can occur during observation.
 29→#[derive(Debug, thiserror::Error)]
 30→pub enum ObserveError {
 31→    #[error("frontend error: {0}")]
 32→    Frontend(#[from] FrontendError),
 33→    #[error("unexpected response from frontend: {0}")]
 34→    UnexpectedResponse(String),
 35→    #[error("instrumentation failed: {0}")]
 36→    InstrumentationFailed(String),
 37→}
 38→
 39→impl From<ExploreError> for ObserveError {
 40→    fn from(e: ExploreError) -> Self {
 41→        match e {
 42→            ExploreError::Frontend(fe) => Self::Frontend(fe),
 43→            ExploreError::UnexpectedResponse(msg) => Self::UnexpectedResponse(msg),
 44→        }
 45→    }
 46→}
 47→
 48→/// Configuration for the observe stage. Contains only execution-related settings;
 49→/// input generation is the caller's responsibility.
 50→#[derive(Debug, Clone)]
 51→pub struct ObserveConfig {
 52→    /// Path to the source file (needed for instrumentation).
 53→    pub file: String,
 54→    /// Mock configurations to pass to Execute commands.
 55→    pub mocks: Vec<MockConfig>,
 56→    /// Path to the setup file, if configured.
 57→    pub setup_file: Option<String>,
 58→    /// When to run setup relative to executions.
 59→    pub setup_level: SetupLevel,
 60→    /// Frontend capabilities (used to gate setup/teardown commands).
 61→    pub capabilities: FrontendCapabilities,
 62→    /// Detected project root directory.
 63→    pub project_root: Option<String>,
 64→    /// Iteration count bucket boundaries for loop-aware path hashing.
 65→    pub loop_buckets: LoopBuckets,
 66→    /// Wall-clock timeout for the entire observation phase.
 67→    pub timeout: Option<Duration>,
 68→    /// Skip the Instrument command (caller already instrumented).
 69→    pub skip_instrument: bool,
 70→}
 71→
 72→impl From<&crate::explorer::ExploreConfig> for ObserveConfig {
 73→    fn from(ec: &crate::explorer::ExploreConfig) -> Self {
 74→        Self {
 75→            file: ec.file.clone(),
 76→            mocks: ec.mocks.clone(),
 77→            setup_file: ec.setup_file.clone(),
 78→            setup_level: ec.setup_level,
 79→            capabilities: ec.capabilities.clone(),
 80→            project_root: ec.project_root.clone(),
 81→            loop_buckets: ec.loop_buckets.clone(),
 82→            timeout: ec.timeout_explore,
 83→            skip_instrument: false,
 84→        }
 85→    }
 86→}
 87→
 88→/// Raw observation results from executing a batch of inputs.
 89→/// Lighter-weight than `ObservationOutput` — no function metadata or summary.
 90→#[derive(Debug, Serialize, Deserialize)]
 91→pub struct BatchObservation {
 92→    /// Every execution result paired with its inputs and mock configs.
 93→    pub raw_results: Vec<(Vec<serde_json::Value>, Vec<MockConfig>, ExecuteResult)>,
 94→    /// Hashes of unique execution paths observed.
 95→    #[serde(skip)]
 96→    pub unique_path_hashes: HashSet<u64>,
 97→    /// Source lines covered across all executions.
 98→    #[serde(skip)]
 99→    pub lines_covered: HashSet<u32>,
100→    /// Per-branch discovery attribution: which branch_id was first seen.
101→    pub discoveries: Vec<(u32, DiscoveryMethod)>,
102→    /// Summaries of executions that discovered new paths.
103→    pub new_path_executions: Vec<ExecutionSummary>,
104→}
105→
106→/// Execute a batch of inputs against an already-instrumented function.
107→///
108→/// This is the lowest-level observation primitive: no instrumentation, no
109→/// setup/teardown lifecycle. The caller manages those concerns.
110→///
111→/// Each input vector is executed sequentially. Returns raw execution data,
112→/// path hashes, line coverage, and discovery attribution.
113→pub async fn observe_batch(
114→    frontend: &mut Frontend,
115→    function_name: &str,
116→    inputs: Vec<Vec<serde_json::Value>>,
117→    mocks: &[MockConfig],
118→    setup_context: Option<&SetupContextStack>,
119→    loop_buckets: &LoopBuckets,
120→    timeout: Option<Duration>,
121→) -> Result<BatchObservation, ObserveError> {
122→    let mut seen_paths: HashSet<u64> = HashSet::new();
123→    let mut all_lines: HashSet<u32> = HashSet::new();
124→    let mut seen_branch_ids: HashSet<u32> = HashSet::new();
125→    let mut discoveries: Vec<(u32, DiscoveryMethod)> = Vec::new();
126→    let mut new_path_executions: Vec<ExecutionSummary> = Vec::new();
127→    let mut raw_results: Vec<(Vec<serde_json::Value>, Vec<MockConfig>, ExecuteResult)> = Vec::new();
128→
129→    let start = Instant::now();
130→
131→    for input in inputs {
132→        if timeout.is_some_and(|t| start.elapsed() >= t) {
133→            break;
134→        }
135→
136→        let response = frontend
137→            .send(ProtoCommand::Execute {
138→                function: function_name.to_string(),
139→                inputs: input.clone(),
140→                mocks: mocks.to_vec(),
141→                setup_context: setup_context.cloned(),
142→            })
143→            .await?;
144→
145→        let exec_result = match response.result {
146→            ResponseResult::Execute(result) => *result,
147→            ResponseResult::Error { code, message, .. } => {
148→                return Err(ObserveError::UnexpectedResponse(format!(
149→                    "execute error ({code:?}): {message}"
150→                )));
151→            }
152→            other => {
153→                return Err(ObserveError::UnexpectedResponse(format!(
154→                    "expected Execute response, got {other:?}"
155→                )));
156→            }
157→        };
158→
159→        for &line in &exec_result.lines_executed {
160→            all_lines.insert(line);
161→        }
162→
163→        let hash = path_hash(&exec_result, loop_buckets);
164→        let is_new = seen_paths.insert(hash);
165→
166→        for decision in &exec_result.branch_path {
167→            if seen_branch_ids.insert(decision.branch_id) {
168→                discoveries.push((decision.branch_id, DiscoveryMethod::Random));
169→            }
170→        }
171→
172→        if is_new {
173→            let error_intent = classify_error_intent(&exec_result);
174→            new_path_executions.push(ExecutionSummary {
175→                inputs: input.clone(),
176→                return_value: exec_result.return_value.clone(),
177→                thrown_error: exec_result
178→                    .thrown_error
179→                    .as_ref()
180→                    .map(|e| format!("{}: {}", e.error_type, e.message)),
181→                lines_executed: exec_result.lines_executed.clone(),
182→                is_new_path: true,
183→                error_intent,
184→            });
185→        }
186→
187→        raw_results.push((input, mocks.to_vec(), exec_result));
188→    }
189→
190→    Ok(BatchObservation {
191→        raw_results,
192→        unique_path_hashes: seen_paths,
193→        lines_covered: all_lines,
194→        discoveries,
195→        new_path_executions,
196→    })
197→}
198→
199→/// Execute a function with pre-generated inputs and collect execution traces.
200→///
201→/// Handles the full observation lifecycle: instrument → setup → execute batch →
202→/// teardown. Returns `ObservationOutput` compatible with the rest of the pipeline.
203→///
204→/// Callers supply pre-generated inputs (random, boundary, user-provided). This
205→/// function does not generate inputs — that separation keeps the observe stage
206→/// composable and testable.
207→pub async fn observe_function(
208→    frontend: &mut Frontend,
209→    analysis: &FunctionAnalysis,
210→    inputs: Vec<Vec<serde_json::Value>>,
211→    config: &ObserveConfig,
212→) -> Result<ObservationOutput, ObserveError> {
213→    let total_input_count = inputs.len() as u32;
214→
215→    // --- Instrumentation ---
216→    let instrumentable_line_count = if config.skip_instrument {
217→        None
218→    } else {
219→        let instrument_response = frontend
220→            .send(ProtoCommand::Instrument {
221→                file: config.file.clone(),
222→                function: analysis.name.clone(),
223→                mocks: config.mocks.clone(),
224→                project_root: config.project_root.clone(),
225→            })
226→            .await?;
227→
228→        match instrument_response.result {
229→            ResponseResult::Instrument {
230→                instrumented,
231→                instrumentable_line_count,
232→                ..
233→            } => {
234→                if !instrumented {
235→                    return Err(ObserveError::InstrumentationFailed(
236→                        "instrumentation returned instrumented=false".to_string(),
237→                    ));
238→                }
239→                instrumentable_line_count
240→            }
241→            ResponseResult::Error { code, message, .. } => {
242→                return Err(ObserveError::InstrumentationFailed(format!(
243→                    "instrument error ({code:?}): {message}"
244→                )));
245→            }
246→            other => {
247→                return Err(ObserveError::UnexpectedResponse(format!(
248→                    "expected Instrument response, got {other:?}"
249→                )));
250→            }
251→        }
252→    };
253→
254→    // --- Setup lifecycle ---
255→    let has_setup =
256→        config.setup_file.is_some() && frontend_supports(&config.capabilities, "setup");
257→    let per_function_setup = has_setup && config.setup_level == SetupLevel::Function;
258→    let per_execution_setup = has_setup && config.setup_level == SetupLevel::Execution;
259→
260→    let mut setup_context: Option<SetupContextStack> = None;
261→
262→    if per_function_setup
263→        && let Some(ref setup_file) = config.setup_file
264→    {
265→        setup_context = send_setup(
266→            frontend,
267→            setup_file,
268→            &analysis.name,
269→            config.setup_level,
270→            config.project_root.clone(),
271→        )
272→        .await?;
273→    }
274→
275→    // --- Execute batch ---
276→    // For per-execution setup, we need to interleave setup/teardown with each execution.
277→    let batch = if per_execution_setup {
278→        observe_batch_with_per_execution_setup(
279→            frontend,
280→            analysis,
281→            inputs,
282→            config,
283→        )
284→        .await?
285→    } else {
286→        observe_batch(
287→            frontend,
288→            &analysis.name,
289→            inputs,
290→            &config.mocks,
291→            setup_context.as_ref(),
292→            &config.loop_buckets,
293→            config.timeout,
294→        )
295→        .await?
296→    };
297→
298→    // --- Per-function teardown ---
299→    if per_function_setup && frontend_supports(&config.capabilities, "teardown") {
300→        send_teardown(frontend, &analysis.name, config.setup_level).await?;
301→    }
302→
303→    let total_lines = instrumentable_line_count
304→        .unwrap_or_else(|| analysis.end_line.saturating_sub(analysis.start_line) + 1);
305→
306→    Ok(ObservationOutput {
307→        function_name: analysis.name.clone(),
308→        iterations: total_input_count,
309→        unique_paths: batch.unique_path_hashes.len(),
310→        lines_covered: batch.lines_covered.len(),
311→        total_lines,
312→        new_path_executions: batch.new_path_executions,
313→        raw_results: batch.raw_results,
314→        discoveries: batch.discoveries,
315→        nondeterministic_fields: vec![],
316→        float_probe_results: vec![],
317→    })
318→}
319→
320→/// Execute inputs with per-execution setup/teardown interleaved.
321→async fn observe_batch_with_per_execution_setup(
322→    frontend: &mut Frontend,
323→    analysis: &FunctionAnalysis,
324→    inputs: Vec<Vec<serde_json::Value>>,
325→    config: &ObserveConfig,
326→) -> Result<BatchObservation, ObserveError> {
327→    let mut seen_paths: HashSet<u64> = HashSet::new();
328→    let mut all_lines: HashSet<u32> = HashSet::new();
329→    let mut seen_branch_ids: HashSet<u32> = HashSet::new();
330→    let mut discoveries: Vec<(u32, DiscoveryMethod)> = Vec::new();
331→    let mut new_path_executions: Vec<ExecutionSummary> = Vec::new();
332→    let mut raw_results: Vec<(Vec<serde_json::Value>, Vec<MockConfig>, ExecuteResult)> = Vec::new();
333→
334→    let start = Instant::now();
335→
336→    for input in inputs {
337→        if config.timeout.is_some_and(|t| start.elapsed() >= t) {
338→            break;
339→        }
340→
341→        // Per-execution setup
342→        let setup_context = if let Some(ref setup_file) = config.setup_file {
343→            send_setup(
344→                frontend,
345→                setup_file,
346→                &analysis.name,
347→                config.setup_level,
348→                config.project_root.clone(),
349→            )
350→            .await?
351→        } else {
352→            None
353→        };
354→
355→        let response = frontend
356→            .send(ProtoCommand::Execute {
357→                function: analysis.name.clone(),
358→                inputs: input.clone(),
359→                mocks: config.mocks.clone(),
360→                setup_context,
361→            })
362→            .await?;
363→
364→        let exec_result = match response.result {
365→            ResponseResult::Execute(result) => *result,
366→            ResponseResult::Error { code, message, .. } => {
367→                return Err(ObserveError::UnexpectedResponse(format!(
368→                    "execute error ({code:?}): {message}"
369→                )));
370→            }
371→            other => {
372→                return Err(ObserveError::UnexpectedResponse(format!(
373→                    "expected Execute response, got {other:?}"
374→                )));
375→            }
376→        };
377→
378→        // Per-execution teardown
379→        if frontend_supports(&config.capabilities, "teardown") {
380→            send_teardown(frontend, &analysis.name, config.setup_level).await?;
381→        }
382→
383→        for &line in &exec_result.lines_executed {
384→            all_lines.insert(line);
385→        }
386→
387→        let hash = path_hash(&exec_result, &config.loop_buckets);
388→        let is_new = seen_paths.insert(hash);
389→
390→        for decision in &exec_result.branch_path {
391→            if seen_branch_ids.insert(decision.branch_id) {
392→                discoveries.push((decision.branch_id, DiscoveryMethod::Random));
393→            }
394→        }
395→
396→        if is_new {
397→            let error_intent = classify_error_intent(&exec_result);
398→            new_path_executions.push(ExecutionSummary {
399→                inputs: input.clone(),
400→                return_value: exec_result.return_value.clone(),
401→                thrown_error: exec_result
402→                    .thrown_error
403→                    .as_ref()
404→                    .map(|e| format!("{}: {}", e.error_type, e.message)),
405→                lines_executed: exec_result.lines_executed.clone(),
406→                is_new_path: true,
407→                error_intent,
408→            });
409→        }
410→
411→        raw_results.push((input, config.mocks.clone(), exec_result));
412→    }
413→
414→    Ok(BatchObservation {
415→        raw_results,
416→        unique_path_hashes: seen_paths,
417→        lines_covered: all_lines,
418→        discoveries,
419→        new_path_executions,
420→    })
421→}
