                    line: id * 10,
                    taken,
                    constraint: SymConstraint::Unknown {
                        hint: String::new(),
                    },
                })
                .collect(),
            lines_executed: lines.to_vec(),
            calls_to_external: vec![],
            path_constraints: vec![],
            scope_events: vec![],
            side_effects: vec![],
            performance: PerformanceMetrics {
                wall_time_ms: 1.0,
                cpu_time_us: 1000,
                heap_used_bytes: 0,
                heap_allocated_bytes: 0,
            },
            capture_truncation: None,
